public func _describe(
  bitmap: Bool = false,
  chains: Bool = false,
  buckets: Bool = false,
) -> String {
  var s = _table.describe(bitmap: bitmap)
  if chains {
    s += "\n"
    s += _chainDescription
  }
  if buckets, !_table.isSmall, !_table.isEmpty {
    s += "\nBuckets:"
    var it = _table.makeBucketIterator()
    var c = 0
    while let next = it.nextOccupiedRegion() {
      var b = next.lowerBound
      while b != next.upperBound {
        if c.isMultiple(of: 8) { s += "\n  " }
        let hashValue = _hashValue(at: b)
        let idealBucket = _table.idealBucket(forHashValue: hashValue)
        let s1 = String(b.offset)._lpad(5)
        let s2 = String(idealBucket.offset)._rpad(5)
        s += "\(s1)→\(s2) "
        c += 1
        b._offset += 1
      }
    }
    s += "\n"
  }
  return s
}

internal mutating func _extend(by n: Int, with paddingBit: Bool = false) {
  assert(n >= 0)
  guard n > 0 else { return }
  let newCount = _count + UInt(n)
  let orig = _storage.count
  let new = _Word.wordCount(forBitCount: newCount)
  if paddingBit == false {
    _storage.append(contentsOf: repeatElement(.empty, count: new - orig))
  } else {
    let (w1, b1) = _BitPosition(_count).split
    let (w2, b2) = _BitPosition(newCount).split
    if w1 < _storage.count {
      _storage[w1].formUnion(_Word(upTo: b1).complement())
    }
    _storage.append(contentsOf: repeatElement(.allBits, count: new - orig))
    if w2 < _storage.count {
      _storage[w2].formIntersection(_Word(upTo: b2))
    }
  }
  _count = newCount
}

@_effects(releasenone)
  @usableFromInline
  package func _bit(ranked n: Int) -> UInt? {
    // FIXME: Use bit deposit instruction when available (PDEP on Intel).
    assert(n >= 0 && n < Self.bitWidth)
    var shift: Self = 0
    var n = Self(truncatingIfNeeded: n)
    let c8 = ((self &>> shift) & 0xFF)._nonzeroBitCount
    if n >= c8 {
      shift &+= 8
      n -= c8
    }
    let c4 = ((self &>> shift) & 0xF)._nonzeroBitCount
    if n >= c4 {
      shift &+= 4
      n -= c4
    }
    let c2 = ((self &>> shift) & 0x3)._nonzeroBitCount
    if n >= c2 {
      shift &+= 2
      n -= c2
    }
    let c1 = (self &>> shift) & 0x1
    if n >= c1 {
      shift &+= 1
      n -= c1
    }
    guard n == 0, (self &>> shift) & 0x1 == 1 else { return nil }
    return UInt(truncatingIfNeeded: shift)
  }

func _foreachChunk(
  from start: Index,
  to end: Index,
  _ body: (UnsafeBufferPointer<UInt8>) -> Void
) {
  precondition(start <= end)
  guard start < end else { return }
  let start = resolve(start, preferEnd: false)
  let end = resolve(end, preferEnd: true)

  var ri = start._rope!
  let endRopeIndex = end._rope!

  if ri == endRopeIndex {
    let buffer = _rope[ri]._bytes.extracting(start._chunkIndex.utf8Offset ..< end._chunkIndex.utf8Offset)
    body(buffer)
    return
  }

  body(_rope[ri]._bytes.extracting(start._chunkIndex.utf8Offset...))

  _rope.formIndex(after: &ri)
  while ri < endRopeIndex {
    body(_rope[ri]._bytes)
    _rope.formIndex(after: &ri)
  }

  body(_rope[ri]._bytes.extracting(..<end._chunkIndex.utf8Offset))
}

func utf16Index(_ i: Index, offsetBy n: Int, limitedBy limit: Index) -> Index? {
  guard limit <= endIndex else {
    return utf16Index(i, offsetBy: n)
  }

  precondition((startIndex ... endIndex).contains(i), "Index out of bounds")

  var i = utf16AlignIndex(i)
  let limit = utf16AlignIndex(limit)

  if n >= 0 {
    for _ in stride(from: 0, to: n, by: 1) {
      if i == limit {
        return nil
      }

      i = utf16Index(after: i)
    }
  } else {
    for _ in stride(from: 0, to: n, by: -1) {
      if i == limit {
        return nil
      }

      i = utf16Index(before: i)
    }
  }

  return i
}

mutating func stepForward() -> Bool {
  guard !isAtEnd else { return false }
  let chunk = _base._rope[_ropeIndex]
  if _next < chunk.endIndex {
    _chunkIndex = _next
    _next = chunk.characterIndex(after: _next)
    return true
  }
  var baseOffset = _utf8BaseOffset + chunk.utf8Count
  var i = _base._rope.index(after: _ropeIndex)
  while i < _base._rope.endIndex {
    let chunk = _base._rope[i]
    let b = chunk.firstBreak
    if b < chunk.endIndex {
      _ropeIndex = i
      _utf8BaseOffset = baseOffset
      _chunkIndex = b
      _next = chunk.characterIndex(after: b, in: b..<chunk.endIndex)
      return true
    }
    baseOffset += chunk.utf8Count
    _base._rope.formIndex(after: &i)
  }
  return false
}

public mutating func next() -> UInt16? {
  guard _index < _base.endIndex else { return nil }
  let ri = _index._rope!
  var ci = _index._chunkIndex
  let chunk = _base._rope[ri]
  let result = chunk[utf16: ci]

  ci = chunk.utf16Index(after: ci)
  if ci < chunk.endIndex {
    _index = BigString.Index(baseUTF8Offset: _index._utf8BaseOffset, _rope: ri, chunk: ci)
  } else {
    _index = BigString.Index(
      baseUTF8Offset: _index._utf8BaseOffset + chunk.utf8Count,
      _rope: _base._rope.index(after: ri),
      chunk: BigString._Chunk.Index(utf8Offset: 0))
  }
  return result
}

public mutating func next() -> UInt8? {
  guard _index < _base.endIndex else { return nil }
  // Hand-optimized from `_base.subscript(utf8:)` and `_base.utf8Index(after:)`.
  let ri = _index._rope!
  var ci = _index._chunkIndex
  let chunk = _base._rope[ri]
  let result = chunk[utf8: ci]

  ci.utf8Offset += 1
  if ci < chunk.endIndex {
    _index = BigString.Index(baseUTF8Offset: _index._utf8BaseOffset, _rope: ri, chunk: ci)
  } else {
    _index = BigString.Index(
      baseUTF8Offset: _index._utf8BaseOffset + chunk.utf8Count,
      _rope: _base._rope.index(after: ri),
      chunk: BigString._Chunk.Index(utf8Offset: 0))
  }
  return result
}

@inlinable
    @_alwaysEmitIntoClient
    public mutating func readMultipleIntegers<T1: FixedWidthInteger, T2: FixedWidthInteger>(
        endianness: Endianness = .big,
        as: (T1, T2).Type = (T1, T2).self
    ) -> (T1, T2)? {
        guard let result = self.getMultipleIntegers(at: self.readerIndex, endianness: endianness, as: `as`) else {
            return nil
        }
        var bytesRequired: Int = MemoryLayout<T1>.size
        bytesRequired &+= MemoryLayout<T2>.size
        self._moveReaderIndex(forwardBy: bytesRequired)
        return result
    }

@inlinable
    @_alwaysEmitIntoClient
    public mutating func readMultipleIntegers<T1: FixedWidthInteger, T2: FixedWidthInteger, T3: FixedWidthInteger>(
        endianness: Endianness = .big,
        as: (T1, T2, T3).Type = (T1, T2, T3).self
    ) -> (T1, T2, T3)? {
        guard let result = self.getMultipleIntegers(at: self.readerIndex, endianness: endianness, as: `as`) else {
            return nil
        }
        var bytesRequired: Int = MemoryLayout<T1>.size
        bytesRequired &+= MemoryLayout<T2>.size
        bytesRequired &+= MemoryLayout<T3>.size
        self._moveReaderIndex(forwardBy: bytesRequired)
        return result
    }

@inlinable
    @_alwaysEmitIntoClient
    public mutating func readMultipleIntegers<
        T1: FixedWidthInteger,
        T2: FixedWidthInteger,
        T3: FixedWidthInteger,
        T4: FixedWidthInteger
    >(endianness: Endianness = .big, as: (T1, T2, T3, T4).Type = (T1, T2, T3, T4).self) -> (T1, T2, T3, T4)? {
        guard let result = self.getMultipleIntegers(at: self.readerIndex, endianness: endianness, as: `as`) else {
            return nil
        }
        var bytesRequired: Int = MemoryLayout<T1>.size
        bytesRequired &+= MemoryLayout<T2>.size
        bytesRequired &+= MemoryLayout<T3>.size
        bytesRequired &+= MemoryLayout<T4>.size
        self._moveReaderIndex(forwardBy: bytesRequired)
        return result
    }

@inlinable
    @_alwaysEmitIntoClient
    public func peekMultipleIntegers<
        T1: FixedWidthInteger,
        T2: FixedWidthInteger,
        T3: FixedWidthInteger,
        T4: FixedWidthInteger,
        T5: FixedWidthInteger,
        T6: FixedWidthInteger,
        T7: FixedWidthInteger
    >(
        endianness: Endianness = .big,
        as: (T1, T2, T3, T4, T5, T6, T7).Type = (T1, T2, T3, T4, T5, T6, T7).self
    ) -> (T1, T2, T3, T4, T5, T6, T7)? {
        self.getMultipleIntegers(at: self.readerIndex, endianness: endianness, as: `as`)
    }

static func pread(
    descriptor: CInt,
    pointer: UnsafeMutableRawPointer,
    size: size_t,
    offset: off_t
) throws -> IOResult<ssize_t> {
    var overlapped = OVERLAPPED()
    // off_t is Int32 anyway. Therefore high is always zero.
    precondition(off_t.self == Int32.self)
    overlapped.OffsetHigh = 0
    overlapped.Offset = UInt32(offset)

    let file = HANDLE(bitPattern: _get_osfhandle(descriptor))
    SetLastError(0)
    var readBytes: DWORD = 0
    let clampedSize = UInt32(clamping: size)
    let rf = ReadFile(file, pointer, clampedSize, &readBytes, &overlapped)
    let lastError = GetLastError()
    if rf == false && lastError != ERROR_HANDLE_EOF {
        throw IOError(errnoCode: Self.windowsErrorToPosixErrno(lastError), reason: "pread")
    }
    return .processed(Int64(readBytes))
}

